VALUES
  ('retired-d0d1b9a2-moex-00010', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司X5年度稅前淨利$250,000，稅率為25%，全年加權平均流通在外普通股為120,000股，', '["認股權證30,000張，每張可以$40認購普通股1股，甲公司 普通股每股全年平均市價為$50", "可轉換公司債面額 $2,000,000，票面利率6%，其中負債組成 部分為$2,000,000（即公司債有效利率亦為 6%），可轉換成 65,000 股普通股", "可轉換累積特 別股30,000股，股利率9%，每股面額$20，可轉換成30,000股普通股，截至X4年底止已積欠2 年股利，X5年甲公司董事會已宣告發放3年股利。甲公司X5年度稀釋每股盈餘為何？", "$1.50"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00011', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司的總經理與財務長於X2年底討論有關公司短期債務的議題，財務長想進行短期債務之再 融資，公司財務報表結束日為X2年12月31日，發布日為X3年3月31日。甲公司將一筆X3 年 7 月 31 日到期的流動負債$8,500,000 與債權人討論，債權人同意展延到期日至 X4 年 8 月 1 日，合約於X2年12月28日簽訂。試問下列何者非為甲公司將短期負債重分類為長期債務將產 生之財務報表影響？', '["降低負債比率", "提高流動比率", "提高速動比率", "提高營運資金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00012', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司銷售電器用品並提供2年期的保固合約，保固合約不與電器用品分開銷售。客戶可要求甲 公司更換損壞的零件並提供必要的人工修理。X5年公司以現金銷售電器用品800台（每台單價 $25,000）。根據過去經驗，甲公司估計每台電器用品保固成本為$1,000（包含人工及零件），X5 年發生保固成本零件$80,000及人工$35,000（均以現金支付）。甲公司應以IAS37號進行會計處 理，但會計人員誤以現金基礎處理，試問此錯誤對甲公司X5年財務報表之影響為何？', '["銷貨收入高估", "負債無影響", "費用低估", "費用無影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00013', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲休閒農場X1年底於市場以每頭$40,000之價格購入乳牛10頭，並另支付運費$7,000將該批乳 牛由市場運回農場，準備飼養以生產牛乳。甲農場估計若同日立即處分該批乳牛，除需支付運費 $7,000將其運回市場外，並需另支付經銷商佣金y元。X1年底當期原始認列生物資產之損失為 $16,000，試問y為何？', '["$0", "$1,000", "$2,000", "$4,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00014', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '下列有關公司發行可轉換公司債與員工認股權之敘述，正確的說明有幾項？', '["發行時都有資本公積之認列", "發行時都有費用科目之認列", "被轉換或被認股時，公司都會收到現金", "被轉換或被認股時，公司都不會有費用科目之認列 ⑤都是由持有人決定是否轉換或認股"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00015', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲工程公司於X1年初以固定價格$800,000承包一項建造合約（履約義務係隨時間逐步滿足）， 預定二年完成該工程。該合約之結果能可靠衡量，其X1、X2年相關資料如下： X1年 X2年 本期發生已完成工作之合約成本 $300,000 b 估計總合約成本 $600,000 c 工程進度請款金額 a d 實際收款金額 $300,000 $500,000 甲公司以至今完工已發生合約成本占估計總合約成本之比例衡量完成程度，X1、X2年分別認列 工程利潤$100,000與$140,000，X1、X2年底之合約資產餘額分別為$50,000與$0，請問b、d金 額分別為何？', '["$560,000、$350,000", "$260,000、$450,000", "$260,000、$350,000", "$560,000、$450,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00016', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司為建造該公司之聯外橋樑，於X1年4月1日向乙銀行專案借款$5,000,000，年利率為4%， 該橋樑係IAS23所述符合要件之資產。甲公司建造之橋樑於X1年5月1日動工並支付工程款， 預計於X2年12月31日完工。X1年8月1日因值當地每年之洪水期導致工程延宕，停工2個 月。試問甲公司X1年應將借款成本資本化的期間有多長？', '["6個月", "7個月", "8個月", "9個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00017', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年1月1日有100,000股普通股（面額$10）與20,000股累積特別股（6%，面額$100） 流通在外。甲公司X1年4月1日現金增資發行4,000股普通股，X1年7月1日將普通股進行 1：2股票分割。X1年度甲公司淨利為$2,278,880，試問甲公司X1年度之每股盈餘為：', '["$10.38", "$10.48", "$10.95", "$11.06"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00018', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司董事會於X1年12月中打算處分冷凍食品部門，惟尚未做成最後決定。X1年冷凍食品部 門營業利益為$100,000。X2年1月中董事會核准並宣布開始執行處分冷凍食品部門，X2年冷凍 食品部門營業損失為$500,000，處分利益為$80,000。假設所得稅率為20%，試問甲公司X1年綜 合損益表列示之停業單位損益為何？', '["$0", "$80,000", "($336,000)", "($400,000)"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00019', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X2 年度損益表中折舊費用為$25,000，出售土地利得$30,000，淨利為$1,350,000，X1 年 12月31日與X2年12月31日的應收帳款餘額分別為$600,000及$650,000，預付費用的餘額分 別為$50,000及 $40,000，應付帳款的餘額分別為$450,000及$380,000，則甲公司X2年度營業活 動所產生的現金流量為：', '["$1,235,000", "$1,265,000", "$1,295,000", "$1,455,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
